import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { 
  LogIn, UserPlus, ShieldCheck, FileText, CheckCircle, 
  X, LogOut, ArrowRight, Activity, Upload, Clock, HelpCircle, LayoutDashboard, Users
} from 'lucide-react';

const Login = () => {
  const [view, setView] = useState('landing'); 
  const [activeTab, setActiveTab] = useState('services'); 
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [userRequests, setUserRequests] = useState([]); 
  const [allRequests, setAllRequests] = useState([]); 
  const [selectedFileName, setSelectedFileName] = useState(""); 

  // FETCH DATA
  const fetchUserRequests = async (userId) => {
    try {
      const res = await axios.get(`http://localhost:5000/api/requests/user/${userId}`);
      setUserRequests(res.data);
    } catch (err) { console.log(err); }
  };

  const fetchAdminData = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/requests/all');
      setAllRequests(res.data); 
    } catch (err) { console.log(err); }
  };

  useEffect(() => {
    const token = localStorage.getItem('token');
    const role = localStorage.getItem('userRole');
    if (token) {
      setIsLoggedIn(true);
      if (role === 'admin') {
        setView('admin-dashboard');
        fetchAdminData();
      } else {
        setView('dashboard');
        fetchUserRequests(localStorage.getItem('userId'));
      }
    }
  }, []);

  // ADMIN ACTION: UPDATE STATUS IN DB
  const updateStatus = async (id, newStatus) => {
    try {
      await axios.put(`http://localhost:5000/api/requests/status/${id}`, { status: newStatus });
      alert(`✅ Request successfully marked as ${newStatus}`);
      fetchAdminData(); // Refresh the real-time list
    } catch (err) { alert("Update Failed"); }
  };

  const handleAuth = async (e) => {
    e.preventDefault();
    const mode = view === 'admin-login' ? 'login' : (view === 'register' ? 'register' : 'login');
    try {
      const res = await axios.post(`http://localhost:5000/api/auth/${mode}`, formData);
      if (mode === 'login') {
        localStorage.setItem('token', res.data.token);
        localStorage.setItem('userRole', res.data.user.role);
        localStorage.setItem('userId', res.data.user._id);
        localStorage.setItem('userName', res.data.user.name);
        setIsLoggedIn(true);
        if (res.data.user.role === 'admin') { setView('admin-dashboard'); fetchAdminData(); }
        else { setView('dashboard'); fetchUserRequests(res.data.user._id); }
      } else { setView('login'); }
    } catch (err) { alert("Invalid Credentials"); }
  };

  const handleNativeUpload = async () => {
    try {
        const [fileHandle] = await window.showOpenFilePicker();
        const file = await fileHandle.getFile();
        setSelectedFileName(file.name);
    } catch (e) {}
  };

  const handleCredentialSubmit = async (e) => {
    e.preventDefault();
    const requestBody = {
      userId: localStorage.getItem('userId'),
      userName: localStorage.getItem('userName'),
      type: e.target[0].value,
      licenseNumber: e.target[1].value,
      documentUrl: selectedFileName || "verification.pdf"
    };
    await axios.post('http://localhost:5000/api/requests/submit', requestBody);
    setShowModal(false);
    fetchUserRequests(localStorage.getItem('userId'));
    setActiveTab('tracking');
  };

  // ADMIN VIEW
  if (view === 'admin-dashboard') {
    return (
      <div className="min-h-screen bg-slate-950 text-white flex flex-col">
        <nav className="p-6 border-b border-slate-900 flex justify-between items-center bg-black/40 sticky top-0 z-50">
          <h1 className="text-xl font-black text-blue-500 uppercase italic">Admin Registry</h1>
          <button onClick={() => {localStorage.clear(); window.location.reload();}} className="bg-red-600/10 text-red-500 border border-red-500/20 px-6 py-2 rounded-xl font-black">Logout</button>
        </nav>
        <main className="p-10 max-w-7xl mx-auto w-full">
           <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
              <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800"><p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">Total Active Apps</p><h4 className="text-4xl font-black">{allRequests.length}</h4></div>
              <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800 border-l-4 border-l-yellow-500"><p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">Pending Verification</p><h4 className="text-4xl font-black text-yellow-500">{allRequests.filter(r => r.status === 'Pending').length}</h4></div>
              <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800 border-l-4 border-l-green-500"><p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">System Efficiency</p><h4 className="text-4xl font-black text-green-500">100%</h4></div>
           </div>

           <div className="bg-slate-900/80 rounded-[3rem] border border-slate-800 overflow-hidden shadow-2xl">
              <table className="w-full text-left">
                <thead className="bg-black/20 text-slate-500 text-[10px] font-black uppercase tracking-widest border-b border-slate-800">
                  <tr><th className="p-8">Provider</th><th className="p-8">Service</th><th className="p-8">Status</th><th className="p-8 text-center">Document</th><th className="p-8 text-right">Actions</th></tr>
                </thead>
                <tbody className="divide-y divide-slate-800/50">
                  {allRequests.map((req) => (
                    <tr key={req._id} className="hover:bg-blue-600/5 transition">
                      <td className="p-8 font-black text-xs uppercase">{req.userName}</td>
                      <td className="p-8 text-slate-400 font-bold text-xs uppercase italic">{req.type}</td>
                      <td className="p-8"><span className={`px-4 py-1 rounded-full text-[9px] font-black uppercase ${req.status === 'Approved' ? 'text-green-500 bg-green-500/10' : (req.status === 'Rejected' ? 'text-red-500 bg-red-500/10' : 'text-yellow-500 bg-yellow-500/10')}`}>{req.status}</span></td>
                      <td className="p-8 text-center text-blue-400 text-[10px] italic underline cursor-pointer"><FileText size={16} className="mx-auto"/> {req.documentUrl}</td>
                      <td className="p-8 text-right space-x-2">
                         <button onClick={() => updateStatus(req._id, 'Approved')} className="bg-green-600 text-white px-3 py-1 rounded-lg text-[9px] font-black uppercase hover:bg-green-500">Approve</button>
                         <button onClick={() => updateStatus(req._id, 'Rejected')} className="bg-red-600/20 text-red-500 px-3 py-1 rounded-lg text-[9px] font-black uppercase border border-red-500/20 hover:bg-red-600 hover:text-white">Reject</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
           </div>
        </main>
      </div>
    );
  }

  // LOGIN / LANDING VIEWS
  if (view === 'landing' || view === 'login' || view === 'register' || view === 'admin-login') {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 text-center">
        {view === 'landing' ? (
          <div className="max-w-4xl w-full">
            <div className="mb-12">
               <div className="inline-block bg-blue-600 p-4 rounded-3xl mb-4 text-white shadow-xl shadow-blue-200"><ShieldCheck size={48} /></div>
               <h1 className="text-5xl font-black text-slate-900 tracking-tight italic uppercase">QUAD SOLUTIONS</h1>
               <p className="text-slate-500 font-medium">Professional Credentialing Portal</p>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div onClick={() => setView('register')} className="bg-white p-10 rounded-[3rem] shadow-xl border-2 border-transparent hover:border-blue-600 cursor-pointer transition text-left group"><UserPlus className="text-blue-600 mb-6 group-hover:scale-110 transition" size={32} /><h2 className="text-2xl font-black text-slate-800 mb-2">New Providers</h2><div className="text-blue-600 font-bold">Start Now <ArrowRight className="inline ml-2"/></div></div>
              <div onClick={() => setView('login')} className="bg-slate-900 text-white p-10 rounded-[3rem] shadow-xl border-2 border-transparent hover:border-blue-400 cursor-pointer transition text-left group"><LogIn className="text-blue-400 mb-6 group-hover:scale-110 transition" size={32} /><h2 className="text-2xl font-black mb-2">Existing Clients</h2><div className="text-blue-400 font-bold">Sign In <ArrowRight className="inline ml-2"/></div></div>
            </div>
            <footer className="mt-20"><button onClick={() => setView('admin-login')} className="flex items-center gap-2 text-slate-300 hover:text-blue-600 transition font-black uppercase text-[10px] bg-white px-6 py-2 rounded-full border border-slate-200"><ShieldCheck size={14}/> Internal Admin Access</button></footer>
          </div>
        ) : (
          <div className="w-full max-w-md bg-white p-10 rounded-[3rem] shadow-2xl relative">
            <button onClick={() => setView('landing')} className="absolute top-8 right-8 text-slate-300 hover:text-slate-600 font-bold">Back</button>
            <h2 className="text-4xl font-black mb-8 text-slate-900 italic">{view === 'admin-login' ? 'Admin Portal' : (view === 'login' ? 'Login' : 'Register')}</h2>
            <form onSubmit={handleAuth} className="space-y-4">
              {view === 'register' && <input type="text" placeholder="Name" className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold" onChange={(e) => setFormData({...formData, name: e.target.value})} required />}
              <input type="email" placeholder="Email" className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold" onChange={(e) => setFormData({...formData, email: e.target.value})} required />
              <input type="password" placeholder="Password" className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold" onChange={(e) => setFormData({...formData, password: e.target.value})} required />
              <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black shadow-xl">Continue</button>
            </form>
          </div>
        )}
      </div>
    );
  }

  // USER DASHBOARD
  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <nav className="bg-white shadow-sm p-4 border-b">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <h1 className="text-xl font-black text-blue-600 italic">QUAD SOLUTIONS</h1>
          <div className="flex gap-4 items-center">
             <button onClick={() => setActiveTab('services')} className={`px-4 py-2 rounded-xl text-sm font-bold ${activeTab === 'services' ? 'bg-blue-600 text-white' : 'text-slate-400'}`}>Services</button>
             <button onClick={() => setActiveTab('tracking')} className={`px-4 py-2 rounded-xl text-sm font-bold ${activeTab === 'tracking' ? 'bg-blue-600 text-white' : 'text-slate-400'}`}>My Status</button>
             <button onClick={() => {localStorage.clear(); window.location.reload();}} className="text-red-500 font-bold p-2 hover:scale-110 transition"><LogOut size={20}/></button>
          </div>
        </div>
      </nav>
      <main className="p-10 max-w-5xl mx-auto w-full">
        {activeTab === 'services' ? (
          <section>
             <h2 className="text-3xl font-black text-slate-900 mb-8 tracking-tighter uppercase italic">Service Catalog</h2>
             <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {['Medical License Renewal', 'Insurance Enrollment', 'DEA Certification'].map((title, idx) => (
                  <div key={idx} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
                    <div className="w-12 h-12 bg-blue-50 rounded-xl flex items-center justify-center mb-4 text-blue-600"><FileText/></div>
                    <h3 className="text-xl font-bold mb-4">{title}</h3>
                    <button onClick={() => setShowModal(true)} className="w-full bg-slate-900 text-white py-3 rounded-xl font-bold hover:bg-blue-600 transition text-[10px] uppercase italic">Apply Now</button>
                  </div>
                ))}
             </div>
          </section>
        ) : (
          <section>
             <h2 className="text-3xl font-black text-slate-900 mb-8 italic uppercase tracking-tighter">Tracking History</h2>
             {userRequests.map((req, idx) => (
               <div key={req._id} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 flex justify-between items-center mb-4">
                  <div className="flex items-center gap-6"><div className="w-16 h-16 bg-slate-900 rounded-3xl flex flex-col items-center justify-center text-white"><span className="text-[9px] font-black opacity-30">REQ</span><span className="text-xl font-black italic">0{idx+1}</span></div><h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter">{req.type}</h3></div>
                  <div className={`px-6 py-2 rounded-xl text-[10px] font-black uppercase ${req.status === 'Approved' ? 'bg-green-100 text-green-600' : (req.status === 'Rejected' ? 'bg-red-100 text-red-600' : 'bg-blue-100 text-blue-600')}`}>{req.status}</div>
               </div>
             ))}
          </section>
        )}
      </main>
      {showModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md flex items-center justify-center p-4 z-[100]">
          <div className="bg-white w-full max-w-md rounded-[3rem] shadow-2xl p-10 animate-in zoom-in duration-200">
            <h2 className="text-2xl font-black mb-6 text-blue-600 uppercase italic">New Application</h2>
            <form onSubmit={handleCredentialSubmit} className="space-y-4">
              <select className="w-full p-4 bg-slate-50 rounded-2xl border-none font-bold text-slate-700 outline-none"><option>Medical License</option><option>Insurance Enrollment</option><option>DEA Certification</option></select>
              <input type="text" placeholder="License ID" className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold" required />
              <div onClick={handleNativeUpload} className="p-8 bg-blue-50 rounded-2xl border-2 border-dashed border-blue-200 text-center cursor-pointer"><Upload className="mx-auto text-blue-400 mb-2" size={28}/><p className="text-[10px] font-black text-blue-600 uppercase">{selectedFileName ? `READY: ${selectedFileName}` : "Select document"}</p></div>
              <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black mt-4 shadow-xl">Submit Application</button>
              <button onClick={() => setShowModal(false)} type="button" className="w-full text-slate-400 font-bold text-sm">Cancel</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Login;
